// WebGPU compat test #2: buffer creation + usage/map-mode constants.
// (Direct writeBuffer‚ÜímapAsync(READ) is unreliable across runtimes ‚Äî even the
// Deno oracle reads zeros without a staging copy + submit ‚Äî so real readback is
// covered by the staging path in the render/readback test #15.)
const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const buf = device.createBuffer({
  size: 32,
  usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST,
});
out.size = buf.size;
out.usageCombined = GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST;
out.mapRead = GPUMapMode.READ;
out.usages = [
  GPUBufferUsage.MAP_READ,
  GPUBufferUsage.COPY_DST,
  GPUBufferUsage.UNIFORM,
  GPUBufferUsage.STORAGE,
];
console.log('__RESULT__ ' + JSON.stringify(out));
